const DB_NAME = 'SiteInspectorDb';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (event) => {
            const database = event.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const inspStore = database.createObjectStore('inspections', { keyPath: 'id' });
                inspStore.createIndex('siteId', 'siteId', { unique: false });
                inspStore.createIndex('isSynced', 'isSynced', { unique: false });
            }
            if (!database.objectStoreNames.contains('checklistItems')) {
                const clStore = database.createObjectStore('checklistItems', { keyPath: 'id' });
                clStore.createIndex('inspectionId', 'inspectionId', { unique: false });
            }
            if (!database.objectStoreNames.contains('photos')) {
                const photoStore = database.createObjectStore('photos', { keyPath: 'id' });
                photoStore.createIndex('inspectionId', 'inspectionId', { unique: false });
                photoStore.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (event) => {
            db = event.target.result;
            resolve(db);
        };
        request.onerror = (event) => reject(event.target.error);
    });
}

window.indexedDbInterop = {
    put: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            const request = store.put(item);
            request.onsuccess = () => resolve(true);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    get: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAll: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getByIndex: async function (storeName, indexName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const index = store.index(indexName);
            const request = index.getAll(key);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    delete: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            const request = store.delete(id);
            request.onsuccess = () => resolve(true);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

window.connectivityInterop = {
    isOnline: function () {
        return navigator.onLine;
    },
    registerOnlineHandler: function (dotNetRef) {
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('OnStatusChanged', true));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('OnStatusChanged', false));
    }
};

window.cameraInterop = {
    capturePhoto: function (videoElementId, canvasElementId) {
        const video = document.getElementById(videoElementId);
        const canvas = document.getElementById(canvasElementId);
        if (!video || !canvas) return null;
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(video, 0, 0);
        return canvas.toDataURL('image/jpeg', 0.7);
    },
    startCamera: async function (videoElementId) {
        try {
            const video = document.getElementById(videoElementId);
            if (!video) return false;
            const stream = await navigator.mediaDevices.getUserMedia({
                video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } }
            });
            video.srcObject = stream;
            await video.play();
            return true;
        } catch (e) {
            console.error('Camera error:', e);
            return false;
        }
    },
    stopCamera: function (videoElementId) {
        const video = document.getElementById(videoElementId);
        if (video && video.srcObject) {
            video.srcObject.getTracks().forEach(t => t.stop());
            video.srcObject = null;
        }
    }
};

