namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly StorageService _storage;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private Timer? _timer;

    public event Action<string>? OnSyncStatusChanged;
    public string LastSyncStatus { get; private set; } = "Not synced";
    public int UnsyncedCount { get; private set; }

    public SyncService(StorageService storage, ConnectivityService connectivity, HttpClient http)
    {
        _storage = storage;
        _connectivity = connectivity;
        _http = http;
    }

    public void StartBackgroundSync()
    {
        _timer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
        _connectivity.OnConnectivityChanged += OnConnectivityChange;
    }

    private async void OnConnectivityChange(bool isOnline)
    {
        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        try
        {
            if (!_connectivity.IsOnline)
            {
                LastSyncStatus = "Offline";
                await UpdateUnsyncedCountAsync();
                OnSyncStatusChanged?.Invoke(LastSyncStatus);
                return;
            }

            var unsyncedInspections = await _storage.GetUnsyncedInspectionsAsync();
            var unsyncedPhotos = await _storage.GetUnsyncedPhotosAsync();
            UnsyncedCount = unsyncedInspections.Count + unsyncedPhotos.Count;

            foreach (var inspection in unsyncedInspections)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkInspectionSyncedAsync(inspection.Id);
                        UnsyncedCount--;
                    }
                }
                catch
                {
                    // Network failure — will retry next cycle
                }
            }

            foreach (var photo in unsyncedPhotos)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/photos", photo);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkPhotoSyncedAsync(photo.Id);
                        UnsyncedCount--;
                    }
                }
                catch
                {
                    // Network failure — will retry next cycle
                }
            }

            LastSyncStatus = UnsyncedCount == 0 ? "All synced" : $"{UnsyncedCount} pending";
            OnSyncStatusChanged?.Invoke(LastSyncStatus);
        }
        catch
        {
            LastSyncStatus = "Sync error";
            OnSyncStatusChanged?.Invoke(LastSyncStatus);
        }
    }

    private async Task UpdateUnsyncedCountAsync()
    {
        try
        {
            var inspections = await _storage.GetUnsyncedInspectionsAsync();
            var photos = await _storage.GetUnsyncedPhotosAsync();
            UnsyncedCount = inspections.Count + photos.Count;
        }
        catch
        {
            // Ignore errors during count
        }
    }

    public void Dispose()
    {
        _timer?.Dispose();
        _connectivity.OnConnectivityChanged -= OnConnectivityChange;
    }
}

