            var unsyncedPhotos = await _storage.GetUnsyncedPhotosAsync();
            UnsyncedCount = unsyncedInspections.Count + unsyncedPhotos.Count;

            foreach (var inspection in unsyncedInspections)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkInspectionSyncedAsync(inspection.Id);
                        UnsyncedCount--;
                    }
                }
                catch
                {
                    // Network failure — will retry next cycle
                }
            }

            foreach (var photo in unsyncedPhotos)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/photos", photo);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkPhotoSyncedAsync(photo.Id);
                        UnsyncedCount--;
                    }
                }
                catch
                {
                    // Network failure — will retry next cycle
                }
            }

            LastSyncStatus = UnsyncedCount == 0 ? "All synced" : $"{UnsyncedCount} pending";
            OnSyncStatusChanged?.Invoke(LastSyncStatus);
        }
        catch
        {
            LastSyncStatus = "Sync error";
            OnSyncStatusChanged?.Invoke(LastSyncStatus);
        }
    }

    private async Task UpdateUnsyncedCountAsync()
    {
        try
        {
            var inspections = await _storage.GetUnsyncedInspectionsAsync();
            var photos = await _storage.GetUnsyncedPhotosAsync();
            UnsyncedCount = inspections.Count + photos.Count;
        }
        catch
        {
            // Ignore errors during count
        }
    }

    public void Dispose()
    {
        _timer?.Dispose();
        _connectivity.OnConnectivityChanged -= OnConnectivityChange;
    }
}

