+
+    public async Task DeleteSiteAsync(Guid id)
+    {
+        await _js.InvokeVoidAsync("indexedDbInterop.delete", "sites", id.ToString());
+    }
+
+    // Inspections
+    public async Task SaveInspectionAsync(Inspection inspection)
+    {
+        var obj = ToJsObject(inspection);
+        await _js.InvokeVoidAsync("indexedDbInterop.put", "inspections", obj);
+    }
+
+    public async Task<List<Inspection>> GetInspectionsBySiteAsync(Guid siteId)
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getByIndex", "inspections", "siteId", siteId.ToString());
+        return Deserialize<List<Inspection>>(result);
+    }
+
+    public async Task<Inspection?> GetInspectionAsync(Guid id)
+    {
+        var result = await _js.InvokeAsync<JsonElement?>("indexedDbInterop.get", "inspections", id.ToString());
+        return result.HasValue ? Deserialize<Inspection>(result.Value) : null;
+    }
+
+    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getByIndex", "inspections", "isSynced", false);
+        return Deserialize<List<Inspection>>(result);
+    }
+
+    public async Task MarkInspectionSyncedAsync(Guid id)
+    {
+        var inspection = await GetInspectionAsync(id);
+        if (inspection != null)
+        {
+            inspection.IsSynced = true;
+            await SaveInspectionAsync(inspection);
+        }
+    }
+
+    // Checklist Items
+    public async Task SaveChecklistItemAsync(ChecklistItem item)
+    {
+        var obj = ToJsObject(item);
+        await _js.InvokeVoidAsync("indexedDbInterop.put", "checklistItems", obj);
+    }
+
+    public async Task<List<ChecklistItem>> GetChecklistItemsByInspectionAsync(Guid inspectionId)
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getByIndex", "checklistItems", "inspectionId", inspectionId.ToString());
+        return Deserialize<List<ChecklistItem>>(result);
+    }
+
+    // Photos
+    public async Task SavePhotoAsync(InspectionPhoto photo)
+    {
+        var obj = ToJsObject(photo);
+        await _js.InvokeVoidAsync("indexedDbInterop.put", "photos", obj);
+    }
+
+    public async Task<List<InspectionPhoto>> GetPhotosByInspectionAsync(Guid inspectionId)
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getByIndex", "photos", "inspectionId", inspectionId.ToString());
+        return Deserialize<List<InspectionPhoto>>(result);
+    }
+
+    public async Task<List<InspectionPhoto>> GetUnsyncedPhotosAsync()
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getByIndex", "photos", "isSynced", false);
+        return Deserialize<List<InspectionPhoto>>(result);
+    }
+
+    public async Task MarkPhotoSyncedAsync(Guid id)
+    {
+        var result = await _js.InvokeAsync<JsonElement?>("indexedDbInterop.get", "photos", id.ToString());
+        if (result.HasValue)
+        {
+            var photo = Deserialize<InspectionPhoto>(result.Value);
+            photo.IsSynced = true;
+            await SavePhotoAsync(photo);
+        }
+    }
+
+    private object ToJsObject<T>(T item)
+    {
+        var json = JsonSerializer.Serialize(item, JsonOptions);
+        return JsonSerializer.Deserialize<JsonElement>(json, JsonOptions);
+    }
+
+    private T Deserialize<T>(JsonElement element) where T : new()
+    {
+        return JsonSerializer.Deserialize<T>(element.GetRawText(), JsonOptions) ?? new T();
+    }
+}
