@inherits LayoutComponentBase

<div class="app-container">
    <header class="top-bar">
        <h1 class="app-title">🏗️ Site Inspector</h1>
        <div class="sync-indicator">
            @if (_isOnline)
            {
                <span class="status-dot online"></span>
                <span class="status-text">@_syncStatus</span>
            }
            else
            {
                <span class="status-dot offline"></span>
                <span class="status-text">Offline</span>
            }
        </div>
    </header>
    <main class="content-area">
        @Body
    </main>
</div>

@code {
    [Inject] private ConnectivityService Connectivity { get; set; } = default!;
    [Inject] private SyncService Sync { get; set; } = default!;

    private bool _isOnline = true;
    private string _syncStatus = "";

    protected override async Task OnInitializedAsync()
    {
        await Connectivity.InitializeAsync();
        _isOnline = Connectivity.IsOnline;

        Connectivity.OnConnectivityChanged += (online) =>
        {
            _isOnline = online;
            InvokeAsync(StateHasChanged);
        };

        Sync.OnSyncStatusChanged += (status) =>
        {
            _syncStatus = status;
            InvokeAsync(StateHasChanged);
        };

        Sync.StartBackgroundSync();
    }
}

@page "/"

<div class="page-header">
    <h2>Construction Sites</h2>
    <button class="btn-primary btn-large" @onclick="ShowAddSite">+ Add Site</button>
</div>

@if (_showAddForm)
{
    <div class="card add-form">
        <input class="input-field" placeholder="Site Name" @bind="_newSiteName" @bind:event="oninput" />
        <input class="input-field" placeholder="Address" @bind="_newSiteAddress" @bind:event="oninput" />
        <div class="form-actions">
            <button class="btn-primary" @onclick="AddSite">Save</button>
            <button class="btn-secondary" @onclick="() => _showAddForm = false">Cancel</button>
        </div>
    </div>
}

@if (_sites.Any())
{
    <div class="site-list">
        @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
        {
            <a class="card site-card" href="@($"site/{site.Id}")">
                <div class="site-name">@site.Name</div>
                <div class="site-address">@site.Address</div>
            </a>
        }
    </div>
}
else if (!_loading)
{
    <div class="empty-state">
        <p>No sites yet. Add your first construction site to get started.</p>
    </div>
}

@if (_unsyncedCount > 0)
{
    <div class="sync-banner">
        <span class="sync-icon">⏳</span> @_unsyncedCount item(s) pending sync
    </div>
}

@code {
    [Inject] private StorageService Storage { get; set; } = default!;
    [Inject] private SyncService Sync { get; set; } = default!;

    private List<Models.Site> _sites = new();
    private bool _showAddForm;
    private string _newSiteName = "";
    private string _newSiteAddress = "";
    private bool _loading = true;
    private int _unsyncedCount;

    protected override async Task OnInitializedAsync()
    {
        await LoadSitesAsync();
        _unsyncedCount = Sync.UnsyncedCount;
        Sync.OnSyncStatusChanged += _ => InvokeAsync(async () =>
        {
            _unsyncedCount = Sync.UnsyncedCount;
            StateHasChanged();
        });
        _loading = false;
    }

    private void ShowAddSite() => _showAddForm = true;

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;
        var site = new Models.Site
        {
            Id = Guid.NewGuid(),
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim(),
            CreatedAt = DateTime.UtcNow
        };
        await Storage.SaveSiteAsync(site);
        _newSiteName = "";
        _newSiteAddress = "";
        _showAddForm = false;
        await LoadSitesAsync();
    }

    private async Task LoadSitesAsync()
    {
        _sites = await Storage.GetAllSitesAsync();
    }
}

@page "/site/{SiteId:guid}"

<div class="page-header">
    <a class="btn-back" href="/">← Back</a>
    <h2>@_site?.Name</h2>
</div>

@if (_site != null)
{
    <div class="card site-info">
        <p><strong>Address:</strong> @_site.Address</p>
        <p><strong>Created:</strong> @_site.CreatedAt.ToLocalTime().ToString("MMM dd, yyyy")</p>
    </div>

    <div class="section-header">
        <h3>Inspections</h3>
        <button class="btn-primary btn-large" @onclick="StartNewInspection">+ New Inspection</button>
    </div>

    @if (_inspections.Any())
    {
        <div class="inspection-list">
            @foreach (var insp in _inspections.OrderByDescending(i => i.StartedAt))
            {
                <a class="card inspection-card" href="@($"inspection/{insp.Id}")">
                    <div class="inspection-header">
                        <span class="inspector-name">@insp.InspectorName</span>
                        <span class="inspection-status @(insp.CompletedAt.HasValue ? "complete" : "in-progress")">
                            @(insp.CompletedAt.HasValue ? "Complete" : "In Progress")
                        </span>
                    </div>
                    <div class="inspection-meta">
                        <span>@insp.StartedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</span>
                        <span class="sync-badge @(insp.IsSynced ? "synced" : "pending")">
                            @(insp.IsSynced ? "✓ Synced" : "⏳ Pending")
                        </span>
                    </div>
                </a>
            }
        </div>
    }
    else
    {
        <div class="empty-state">
            <p>No inspections yet. Start your first inspection.</p>
        </div>
    }
}

@code {
    [Parameter] public Guid SiteId { get; set; }
    [Inject] private StorageService Storage { get; set; } = default!;
    [Inject] private NavigationManager Nav { get; set; } = default!;

    private Models.Site? _site;
    private List<Models.Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        _site = await Storage.GetSiteAsync(SiteId);
        _inspections = await Storage.GetInspectionsBySiteAsync(SiteId);
    }

    private void StartNewInspection()
    {
        var id = Guid.NewGuid();
        Nav.NavigateTo($"inspection/{id}?siteId={SiteId}");
    }
}

@page "/inspection/{InspectionId:guid}"

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h2>Inspection</h2>
</div>

<div class="inspection-form">
    <div class="card">
        <label class="field-label">Inspector Name</label>
        <input class="input-field" placeholder="Your name" @bind="_inspection.InspectorName"
               @bind:event="oninput" @onfocusout="SaveInspection" />
    </div>

    @foreach (var category in _categories)
    {
        <div class="card checklist-category">
            <button class="category-header" @onclick="() => ToggleCategory(category)">
                <span class="category-name">@category</span>
                <span class="category-progress">@GetCategoryProgress(category)</span>
                <span class="collapse-icon">@(_expandedCategories.Contains(category) ? "▼" : "▶")</span>
            </button>

            @if (_expandedCategories.Contains(category))
            {
                <div class="checklist-items">
                    @foreach (var item in _checklistItems.Where(i => i.Category == category))
                    {
                        <div class="checklist-item">
                            <div class="item-description">@item.Description</div>
                            <div class="status-buttons">
                                <button class="status-btn pass @(item.Status == Models.CheckStatus.Pass ? "active" : "")"
                                        @onclick="() => SetStatus(item, Models.CheckStatus.Pass)">✓</button>
                                <button class="status-btn fail @(item.Status == Models.CheckStatus.Fail ? "active" : "")"
                                        @onclick="() => SetStatus(item, Models.CheckStatus.Fail)">✗</button>
                                <button class="status-btn na @(item.Status == Models.CheckStatus.NotApplicable ? "active" : "")"
                                        @onclick="() => SetStatus(item, Models.CheckStatus.NotApplicable)">N/A</button>
                            </div>
                            <div class="item-actions">
                                <button class="btn-small" @onclick="() => ToggleNotes(item.Id)">📝 Notes</button>
                                <button class="btn-small" @onclick="() => OpenCamera(item.Id)">📷 Photo</button>
                            </div>
                            @if (_expandedNotes.Contains(item.Id))
                            {
                                <textarea class="item-notes" placeholder="Add notes..."
                                          @bind="item.Notes" @bind:event="oninput"
                                          @onfocusout="() => SaveChecklistItem(item)"></textarea>
                            }
                        </div>
                    }
                </div>
            }
        </div>
    }

    <div class="card">
        <label class="field-label">General Notes</label>
        <textarea class="input-field notes-field" placeholder="General inspection notes..."
                  @bind="_inspection.Notes" @bind:event="oninput"
                  @onfocusout="SaveInspection"></textarea>
    </div>

    @if (!_inspection.CompletedAt.HasValue)
    {
        <button class="btn-primary btn-large btn-complete" @onclick="CompleteInspection">
            ✓ Complete Inspection
        </button>
    }
    else
    {
        <div class="completed-banner">✓ Inspection completed @_inspection.CompletedAt.Value.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</div>
    }
</div>

@if (_showCamera)
{
    <PhotoCapture OnPhotoCaptured="OnPhotoCaptured" OnClose="() => _showCamera = false" />
}

@code {
    [Parameter] public Guid InspectionId { get; set; }
    [Inject] private StorageService Storage { get; set; } = default!;
    [Inject] private ChecklistTemplateService Templates { get; set; } = default!;
    [Inject] private NavigationManager Nav { get; set; } = default!;

    private Models.Inspection _inspection = new();
    private List<Models.ChecklistItem> _checklistItems = new();
    private List<string> _categories = new();
    private HashSet<string> _expandedCategories = new();
    private HashSet<Guid> _expandedNotes = new();
    private bool _showCamera;
    private Guid? _cameraItemId;
    private Guid _siteId;

    protected override async Task OnInitializedAsync()
    {
        var uri = new Uri(Nav.Uri);
        var query = System.Web.HttpUtility.ParseQueryString(uri.Query);
        var siteIdParam = query["siteId"];

        var existing = await Storage.GetInspectionAsync(InspectionId);
        if (existing != null)
        {
            _inspection = existing;
            _siteId = _inspection.SiteId;
            _checklistItems = await Storage.GetChecklistItemsByInspectionAsync(InspectionId);
            _categories = _checklistItems.Select(i => i.Category).Distinct().ToList();
        }
        else
        {
            _siteId = siteIdParam != null ? Guid.Parse(siteIdParam) : Guid.Empty;
            _inspection = new Models.Inspection
            {
                Id = InspectionId,
                SiteId = _siteId,
                StartedAt = DateTime.UtcNow,
                InspectorName = ""
            };
            await Storage.SaveInspectionAsync(_inspection);

            var templates = Templates.GetTemplates();
            foreach (var template in templates)
            {
                foreach (var desc in template.Items)
                {
                    var item = new Models.ChecklistItem
                    {
                        Id = Guid.NewGuid(),
                        InspectionId = InspectionId,
                        Category = template.Category,
                        Description = desc,
                        Status = Models.CheckStatus.NotChecked
                    };
                    _checklistItems.Add(item);
                    await Storage.SaveChecklistItemAsync(item);
                }
            }
            _categories = templates.Select(t => t.Category).ToList();
        }

        // Expand first category by default
        if (_categories.Any())
            _expandedCategories.Add(_categories.First());
    }

    private void ToggleCategory(string category)
    {
        if (!_expandedCategories.Add(category))
            _expandedCategories.Remove(category);
    }

    private void ToggleNotes(Guid itemId)
    {
        if (!_expandedNotes.Add(itemId))
            _expandedNotes.Remove(itemId);
    }

    private async Task SetStatus(Models.ChecklistItem item, Models.CheckStatus status)
    {
        item.Status = status;
        item.CheckedAt = DateTime.UtcNow;
        await SaveChecklistItem(item);
    }

    private async Task SaveChecklistItem(Models.ChecklistItem item)
    {
        await Storage.SaveChecklistItemAsync(item);
    }

    private async Task SaveInspection()
    {
        await Storage.SaveInspectionAsync(_inspection);
    }

    private async Task CompleteInspection()
    {
        _inspection.CompletedAt = DateTime.UtcNow;
        await Storage.SaveInspectionAsync(_inspection);
    }

    private void OpenCamera(Guid itemId)
    {
        _cameraItemId = itemId;
        _showCamera = true;
    }

    private async Task OnPhotoCaptured(string base64Data)
    {
        var photo = new Models.InspectionPhoto
        {
            Id = Guid.NewGuid(),
            InspectionId = InspectionId,
            ChecklistItemId = _cameraItemId,
            FileName = $"photo_{DateTime.UtcNow:yyyyMMdd_HHmmss}.jpg",
            Base64Data = base64Data,
            CapturedAt = DateTime.UtcNow,
            IsSynced = false
        };
        await Storage.SavePhotoAsync(photo);
        _showCamera = false;
    }

    private void GoBack()
    {
        Nav.NavigateTo($"site/{_siteId}");
    }

    private string GetCategoryProgress(string category)
    {
        var items = _checklistItems.Where(i => i.Category == category).ToList();
        var checked = items.Count(i => i.Status != Models.CheckStatus.NotChecked);
        return $"{checked}/{items.Count}";
    }
}

@using Microsoft.JSInterop

<div class="camera-overlay">
    <div class="camera-container">
        <div class="camera-header">
            <h3>Capture Photo</h3>
            <button class="btn-close" @onclick="Close">✕</button>
        </div>
        <video id="camera-video" autoplay playsinline></video>
        <canvas id="camera-canvas" style="display:none;"></canvas>
        @if (!string.IsNullOrEmpty(_preview))
        {
            <img class="photo-preview" src="@_preview" alt="Preview" />
        }
        <div class="camera-actions">
            @if (string.IsNullOrEmpty(_preview))
            {
                <button class="btn-primary btn-large" @onclick="Capture">📷 Capture</button>
            }
            else
            {
                <button class="btn-primary btn-large" @onclick="Accept">✓ Use Photo</button>
                <button class="btn-secondary btn-large" @onclick="Retake">↻ Retake</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter] public EventCallback<string> OnPhotoCaptured { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }
    [Inject] private IJSRuntime JS { get; set; } = default!;

    private string? _preview;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await JS.InvokeAsync<bool>("cameraInterop.startCamera", "camera-video");
        }
    }

    private async Task Capture()
    {
        _preview = await JS.InvokeAsync<string>("cameraInterop.capturePhoto", "camera-video", "camera-canvas");
    }

    private async Task Retake()
    {
        _preview = null;
        await JS.InvokeAsync<bool>("cameraInterop.startCamera", "camera-video");
    }

    private async Task Accept()
    {
        if (_preview != null)
        {
            // Strip the data:image/jpeg;base64, prefix
            var base64 = _preview.Contains(",") ? _preview.Split(',')[1] : _preview;
            await OnPhotoCaptured.InvokeAsync(base64);
        }
    }

    private async Task Close()
    {
        await JS.InvokeVoidAsync("cameraInterop.stopCamera", "camera-video");
        await OnClose.InvokeAsync();
    }
}

