+                  @bind="_inspection.Notes" @bind:event="oninput"
+                  @onfocusout="SaveInspection"></textarea>
+    </div>
+
+    @if (!_inspection.CompletedAt.HasValue)
+    {
+        <button class="btn-primary btn-large btn-complete" @onclick="CompleteInspection">
+            ✓ Complete Inspection
+        </button>
+    }
+    else
+    {
+        <div class="completed-banner">✓ Inspection completed @_inspection.CompletedAt.Value.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</div>
+    }
