+@using Microsoft.JSInterop
+
+<div class="camera-overlay">
+    <div class="camera-container">
+        <div class="camera-header">
+            <h3>Capture Photo</h3>
+            <button class="btn-close" @onclick="Close">✕</button>
+        </div>
+        <video id="camera-video" autoplay playsinline></video>
+        <canvas id="camera-canvas" style="display:none;"></canvas>
+        @if (!string.IsNullOrEmpty(_preview))
+        {
+            <img class="photo-preview" src="@_preview" alt="Preview" />
+        }
+        <div class="camera-actions">
+            @if (string.IsNullOrEmpty(_preview))
+            {
+                <button class="btn-primary btn-large" @onclick="Capture">📷 Capture</button>
+            }
+            else
+            {
+                <button class="btn-primary btn-large" @onclick="Accept">✓ Use Photo</button>
+                <button class="btn-secondary btn-large" @onclick="Retake">↻ Retake</button>
+            }
+        </div>
+    </div>
+</div>
+
+@code {
+    [Parameter] public EventCallback<string> OnPhotoCaptured { get; set; }
+    [Parameter] public EventCallback OnClose { get; set; }
+    [Inject] private IJSRuntime JS { get; set; } = default!;
+
+    private string? _preview;
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+        {
+            await JS.InvokeAsync<bool>("cameraInterop.startCamera", "camera-video");
+        }
+    }
+
+    private async Task Capture()
+    {
+        _preview = await JS.InvokeAsync<string>("cameraInterop.capturePhoto", "camera-video", "camera-canvas");
+    }
+
+    private async Task Retake()
+    {
+        _preview = null;
+        await JS.InvokeAsync<bool>("cameraInterop.startCamera", "camera-video");
+    }
+
+    private async Task Accept()
+    {
+        if (_preview != null)
+        {
+            // Strip the data:image/jpeg;base64, prefix
+            var base64 = _preview.Contains(",") ? _preview.Split(',')[1] : _preview;
+            await OnPhotoCaptured.InvokeAsync(base64);
+        }
+    }
+
+    private async Task Close()
+    {
+        await JS.InvokeVoidAsync("cameraInterop.stopCamera", "camera-video");
+        await OnClose.InvokeAsync();
+    }
+}
+

