@inherits LayoutComponentBase

<div class="app-container">
    <header class="top-bar">
        <h1 class="app-title">🏗️ Site Inspector</h1>
        <div class="sync-indicator">
            @if (_isOnline)
            {
                <span class="status-dot online"></span>
                <span class="status-text">@_syncStatus</span>
            }
            else
            {
                <span class="status-dot offline"></span>
                <span class="status-text">Offline</span>
            }
        </div>
    </header>
    <main class="content-area">
        @Body
    </main>
</div>

@code {
    [Inject] private ConnectivityService Connectivity { get; set; } = default!;
    [Inject] private SyncService Sync { get; set; } = default!;

    private bool _isOnline = true;
    private string _syncStatus = "";

    protected override async Task OnInitializedAsync()
    {
        await Connectivity.InitializeAsync();
        _isOnline = Connectivity.IsOnline;

        Connectivity.OnConnectivityChanged += (online) =>
        {
            _isOnline = online;
            InvokeAsync(StateHasChanged);
        };

        Sync.OnSyncStatusChanged += (status) =>
        {
            _syncStatus = status;
            InvokeAsync(StateHasChanged);
        };

        Sync.StartBackgroundSync();
    }
}

@page "/"

<div class="page-header">
    <h2>Construction Sites</h2>
    <button class="btn-primary btn-large" @onclick="ShowAddSite">+ Add Site</button>
</div>

@if (_showAddForm)
{
    <div class="card add-form">
        <input class="input-field" placeholder="Site Name" @bind="_newSiteName" @bind:event="oninput" />
        <input class="input-field" placeholder="Address" @bind="_newSiteAddress" @bind:event="oninput" />
        <div class="form-actions">
            <button class="btn-primary" @onclick="AddSite">Save</button>
            <button class="btn-secondary" @onclick="() => _showAddForm = false">Cancel</button>
        </div>
    </div>
}

@if (_sites.Any())
{
    <div class="site-list">
        @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
        {
            <a class="card site-card" href="@($"site/{site.Id}")">
                <div class="site-name">@site.Name</div>
                <div class="site-address">@site.Address</div>
            </a>
        }
    </div>
}
else if (!_loading)
{
    <div class="empty-state">
        <p>No sites yet. Add your first construction site to get started.</p>
    </div>
}

@if (_unsyncedCount > 0)
{
    <div class="sync-banner">
        <span class="sync-icon">⏳</span> @_unsyncedCount item(s) pending sync
    </div>
}

@code {
    [Inject] private StorageService Storage { get; set; } = default!;
    [Inject] private SyncService Sync { get; set; } = default!;

    private List<Models.Site> _sites = new();
    private bool _showAddForm;
    private string _newSiteName = "";
    private string _newSiteAddress = "";
    private bool _loading = true;
    private int _unsyncedCount;

    protected override async Task OnInitializedAsync()
    {
        await LoadSitesAsync();
        _unsyncedCount = Sync.UnsyncedCount;
        Sync.OnSyncStatusChanged += _ => InvokeAsync(async () =>
        {
            _unsyncedCount = Sync.UnsyncedCount;
            StateHasChanged();
        });
        _loading = false;
    }

    private void ShowAddSite() => _showAddForm = true;

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;
        var site = new Models.Site
        {
            Id = Guid.NewGuid(),
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim(),
            CreatedAt = DateTime.UtcNow
        };
        await Storage.SaveSiteAsync(site);
        _newSiteName = "";
        _newSiteAddress = "";
        _showAddForm = false;
        await LoadSitesAsync();
    }

    private async Task LoadSitesAsync()
    {
        _sites = await Storage.GetAllSitesAsync();
    }
}

