@code {
    [Inject] private StorageService Storage { get; set; } = default!;
    [Inject] private SyncService Sync { get; set; } = default!;

    private List<Models.Site> _sites = new();
    private bool _showAddForm;
    private string _newSiteName = "";
    private string _newSiteAddress = "";
    private bool _loading = true;
    private int _unsyncedCount;

    protected override async Task OnInitializedAsync()
    {
        await LoadSitesAsync();
        _unsyncedCount = Sync.UnsyncedCount;
        Sync.OnSyncStatusChanged += _ => InvokeAsync(async () =>
        {
            _unsyncedCount = Sync.UnsyncedCount;
            StateHasChanged();
        });
        _loading = false;
    }

    private void ShowAddSite() => _showAddForm = true;

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;
        var site = new Models.Site
        {
            Id = Guid.NewGuid(),
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim(),
            CreatedAt = DateTime.UtcNow
        };
        await Storage.SaveSiteAsync(site);
        _newSiteName = "";
        _newSiteAddress = "";
        _showAddForm = false;
        await LoadSitesAsync();
    }

    private async Task LoadSitesAsync()
    {
        _sites = await Storage.GetAllSitesAsync();
    }
}

